int array_sum(int n, int *a)
/*@ With l
    Require
      0 <= n && n <= 10000 &&
      Zlength(l) == n &&
      (forall (i: Z), (0 <= i && i < n) => (-10000 <= l[i] && l[i] <= 10000)) &&
      -2147483648 <= sum(l) && sum(l) <= 2147483647 &&
      IntArray::full(a, n, l)
    Ensure
      __return == sum(l) && IntArray::full(a, n, l)
*/
{
    int i;
    int ret = 0;

    /*@ Inv
          0 <= i && i <= n &&
          a == a@pre &&
          n == n@pre &&
          ret == sum(sublist(0, i, l)) &&
          IntArray::full(a, n, l)
    */
    for (i = 0; i < n; ++i) {
        ret += a[i];
    }

    /*@ Assert
          i == n &&
          a == a@pre &&
          n == n@pre &&
          ret == sum(l) &&
          IntArray::full(a, n, l)
    */
    return ret;
}

